        public void Creat_XYZ_From_sszn_COPY_New_COPY_1(HObject ho_ImageZ, out HObject ho_ImageConvertedX,
            out HObject ho_ImageConvertedY, out HObject ho_ImageReducedZ1, HTuple hv_yInterval,
            out HTuple hv_ObjectModel3D)
        {




            // Local iconic variables 

            HObject ho_ImageX, ho_ImageY, ho_ImageConvertedZ;
            HObject ho_Region, ho_ImageReducedZ;

            // Local control variables 

            HTuple hv_Width = new HTuple(), hv_Height = new HTuple();
            HTuple hv_xInterval = new HTuple(), hv_Min = new HTuple();
            HTuple hv_Max = new HTuple(), hv_Range = new HTuple();
            HTuple hv_ScaleZ = new HTuple();
            // Initialize local and output iconic variables 
            HOperatorSet.GenEmptyObj(out ho_ImageConvertedX);
            HOperatorSet.GenEmptyObj(out ho_ImageConvertedY);
            HOperatorSet.GenEmptyObj(out ho_ImageReducedZ1);
            HOperatorSet.GenEmptyObj(out ho_ImageX);
            HOperatorSet.GenEmptyObj(out ho_ImageY);
            HOperatorSet.GenEmptyObj(out ho_ImageConvertedZ);
            HOperatorSet.GenEmptyObj(out ho_Region);
            HOperatorSet.GenEmptyObj(out ho_ImageReducedZ);
            hv_ObjectModel3D = new HTuple();
            try
            {
                hv_Width.Dispose(); hv_Height.Dispose();
                HOperatorSet.GetImageSize(ho_ImageZ, out hv_Width, out hv_Height);

                //鐢熸垚XY鍥惧儚
                hv_xInterval.Dispose();
                hv_xInterval = 0.015;
                //yInterval := 0.09
                ho_ImageX.Dispose();
                HOperatorSet.GenImageSurfaceFirstOrder(out ho_ImageX, "real", 0, hv_xInterval,
                    0, 0, 0, hv_Width, hv_Height);
                ho_ImageY.Dispose();
                HOperatorSet.GenImageSurfaceFirstOrder(out ho_ImageY, "real", hv_yInterval,
                    0, 0, 0, 0, hv_Width, hv_Height);

                //瀵逛簬real绫诲瀷鐨勫浘鍍忎笉鍐嶉渶瑕佷竴涓嬫搷浣�
                ho_ImageConvertedX.Dispose();
                HOperatorSet.ConvertImageType(ho_ImageX, out ho_ImageConvertedX, "real");
                ho_ImageConvertedY.Dispose();
                HOperatorSet.ConvertImageType(ho_ImageY, out ho_ImageConvertedY, "real");
                ho_ImageConvertedZ.Dispose();
                HOperatorSet.ConvertImageType(ho_ImageZ, out ho_ImageConvertedZ, "real");

                //璁＄畻鏁版嵁鏈€澶ф渶灏忓€�
                hv_Min.Dispose(); hv_Max.Dispose(); hv_Range.Dispose();
                HOperatorSet.MinMaxGray(ho_ImageZ, ho_ImageZ, 0, out hv_Min, out hv_Max, out hv_Range);
                ho_Region.Dispose();
                HOperatorSet.Threshold(ho_ImageZ, out ho_Region, -30, 500);
                ho_ImageReducedZ.Dispose();
                HOperatorSet.ReduceDomain(ho_ImageZ, ho_Region, out ho_ImageReducedZ);
                //璁剧疆Z鏂瑰悜缂╂斁绯绘暟,鏈€缁堥珮搴� = ScaleZ * GrayValue鍊硷紝ScaleZ瓒婂皬楂樺害鍊艰寖鍥翠篃瓒婂皬锛岀偣浜戞晥鏋滄帴杩戝钩闈紝鍙嶄箣瓒婃槑鏄�
                //纭繚鍦�0鍊间互涓婏紝鍙€氳繃min_max_gray鑾峰彇鏈€灏忓€肩劧鍚庢媺浼稿埌0浠ヤ笂
                hv_ScaleZ.Dispose();
                hv_ScaleZ = 1;
                ho_ImageReducedZ1.Dispose();
                HOperatorSet.ScaleImage(ho_ImageReducedZ, out ho_ImageReducedZ1, hv_ScaleZ,
                    0);
                hv_ObjectModel3D.Dispose();
                HOperatorSet.XyzToObjectModel3d(ho_ImageConvertedX, ho_ImageConvertedY, ho_ImageReducedZ1,
                    out hv_ObjectModel3D);

                ho_ImageX.Dispose();
                ho_ImageY.Dispose();
                ho_ImageConvertedZ.Dispose();
                ho_Region.Dispose();
                ho_ImageReducedZ.Dispose();

                hv_Width.Dispose();
                hv_Height.Dispose();
                hv_xInterval.Dispose();
                hv_Min.Dispose();
                hv_Max.Dispose();
                hv_Range.Dispose();
                hv_ScaleZ.Dispose();

                return;

            }
            catch (HalconException HDevExpDefaultException)
            {
                ho_ImageX.Dispose();
                ho_ImageY.Dispose();
                ho_ImageConvertedZ.Dispose();
                ho_Region.Dispose();
                ho_ImageReducedZ.Dispose();

                hv_Width.Dispose();
                hv_Height.Dispose();
                hv_xInterval.Dispose();
                hv_Min.Dispose();
                hv_Max.Dispose();
                hv_Range.Dispose();
                hv_ScaleZ.Dispose();

            }
        }


        public void project_object_model_3d_lines_to_contour_xld(out HObject ho_Intersection,
      HTuple hv_PoseIntersectionPlane, HTuple hv_ObjectModel3DIntersection, out HTuple hv_resultcon)
        {



            // Local iconic variables 

            // Local control variables 

            HTuple hv_PoseInvert = new HTuple(), hv_hasPoint = new HTuple();
            HTuple hv_Diameter = new HTuple(), hv_Exception = new HTuple();
            HTuple hv_Scale = new HTuple(), hv_CamParam = new HTuple();
            // Initialize local and output iconic variables 
            HOperatorSet.GenEmptyObj(out ho_Intersection);
            hv_resultcon = new HTuple();
            try
            {

                //Determine the intersections and convert them into XLD contours

                //The inverted intersection plane pose is our projection pose
                hv_PoseInvert.Dispose();
                HOperatorSet.PoseInvert(hv_PoseIntersectionPlane, out hv_PoseInvert);
                //Make sure, the projection plane lies in front of the camera
                try
                {
                    hv_hasPoint.Dispose();
                    HOperatorSet.GetObjectModel3dParams(hv_ObjectModel3DIntersection, "has_points",
                        out hv_hasPoint);
                    if ((int)(new HTuple(hv_hasPoint.TupleEqual("true"))) != 0)
                    {
                        hv_Diameter.Dispose();
                        HOperatorSet.GetObjectModel3dParams(hv_ObjectModel3DIntersection, "diameter_axis_aligned_bounding_box",
                            out hv_Diameter);
                    }
                    else
                    {
                        hv_resultcon.Dispose();
                        hv_resultcon = 0;

                        hv_PoseInvert.Dispose();
                        hv_hasPoint.Dispose();
                        hv_Diameter.Dispose();
                        hv_Exception.Dispose();
                        hv_Scale.Dispose();
                        hv_CamParam.Dispose();

                        return;
                    }

                }
                // catch (Exception) 
                catch (HalconException HDevExpDefaultException1)
                {
                    HDevExpDefaultException1.ToHTuple(out hv_Exception);
                    hv_resultcon.Dispose();
                    hv_resultcon = 0;

                    hv_PoseInvert.Dispose();
                    hv_hasPoint.Dispose();
                    hv_Diameter.Dispose();
                    hv_Exception.Dispose();
                    hv_Scale.Dispose();
                    hv_CamParam.Dispose();

                    return;
                }
                if (hv_PoseInvert == null)
                    hv_PoseInvert = new HTuple();
                hv_PoseInvert[2] = (hv_PoseInvert.TupleSelect(2)) + hv_Diameter;
                //Use a parallel projection to achieve the desired scaling (default 1:1)
                hv_Scale.Dispose();
                hv_Scale = 1;
                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                {
                    hv_CamParam.Dispose();
                    hv_CamParam = hv_CamParam.TupleConcat(new HTuple[] { "area_scan_telecentric_division", 1.0, 0, 1.0 / hv_Scale, 1.0 / hv_Scale, 0, 0, 512, 512 });

                    //gen_cam_par_area_scan_telecentric_division(1.0, 0, 1.0 / hv_Scale, 1.0 / hv_Scale,0, 0, 512, 512, out hv_CamParam);
                }
                ho_Intersection.Dispose();
                HOperatorSet.ProjectObjectModel3d(out ho_Intersection, hv_ObjectModel3DIntersection,
                    hv_CamParam, hv_PoseInvert, "data", "lines");
                hv_resultcon.Dispose();
                hv_resultcon = 1;

                hv_PoseInvert.Dispose();
                hv_hasPoint.Dispose();
                hv_Diameter.Dispose();
                hv_Exception.Dispose();
                hv_Scale.Dispose();
                hv_CamParam.Dispose();

                return;
            }
            catch (HalconException HDevExpDefaultException)
            {

                hv_PoseInvert.Dispose();
                hv_hasPoint.Dispose();
                hv_Diameter.Dispose();
                hv_Exception.Dispose();
                hv_Scale.Dispose();
                hv_CamParam.Dispose();

            }
        }

        public void Deal3DFunc(HObject ho_Image, HTuple hv_SampleDistance, HTuple hv_valueDistance,
      HTuple hv_yInterval, out HTuple hv_Sample3DModule)
        {




            // Local iconic variables 

            HObject ho_Bx, ho_By, ho_Bz;

            // Local control variables 

            HTuple hv_Sample3DModuleTmp = new HTuple();
            HTuple hv_ObjectModel3DBLeft = new HTuple(), hv_ObjectModel3DBLeftConnected = new HTuple();
            HTuple hv_ObjectModel3DBLeftNew = new HTuple(), hv_Info = new HTuple();
            // Initialize local and output iconic variables 
            HOperatorSet.GenEmptyObj(out ho_Bx);
            HOperatorSet.GenEmptyObj(out ho_By);
            HOperatorSet.GenEmptyObj(out ho_Bz);
            hv_Sample3DModule = new HTuple();
            try
            {

                //sample_object_model_3d (Tmp3DModule, 'fast_compute_normals', 0.12, [], [], Sample3DModuleTmp)
                ho_Bx.Dispose(); ho_By.Dispose(); ho_Bz.Dispose(); hv_ObjectModel3DBLeft.Dispose();
                Creat_XYZ_From_sszn_COPY_New_COPY_1(ho_Image, out ho_Bx, out ho_By, out ho_Bz,
                    hv_yInterval, out hv_ObjectModel3DBLeft);
                hv_ObjectModel3DBLeftConnected.Dispose();
                HOperatorSet.ConnectionObjectModel3d(hv_ObjectModel3DBLeft, "distance_3d",
                    hv_valueDistance, out hv_ObjectModel3DBLeftConnected);
                hv_ObjectModel3DBLeftNew.Dispose();
                HOperatorSet.SelectObjectModel3d(hv_ObjectModel3DBLeftConnected, "num_points",
                    "and", 200000, 1e100, out hv_ObjectModel3DBLeftNew);

                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                {
                    hv_Sample3DModuleTmp.Dispose();
                    HOperatorSet.SampleObjectModel3d(hv_ObjectModel3DBLeftNew.TupleSelect(0), "fast",
                        hv_SampleDistance, new HTuple(), new HTuple(), out hv_Sample3DModuleTmp);
                }
                hv_Sample3DModule.Dispose(); hv_Info.Dispose();
                HOperatorSet.TriangulateObjectModel3d(hv_Sample3DModuleTmp, "greedy", new HTuple(),
                    new HTuple(), out hv_Sample3DModule, out hv_Info);
                //get_object_model_3d_params (Sample3DModule, 'point_coord_x', Xt)


                ho_Bx.Dispose();
                ho_By.Dispose();
                ho_Bz.Dispose();

                hv_Sample3DModuleTmp.Dispose();
                hv_ObjectModel3DBLeft.Dispose();
                hv_ObjectModel3DBLeftConnected.Dispose();
                hv_ObjectModel3DBLeftNew.Dispose();
                hv_Info.Dispose();

                return;
            }
            catch (HalconException HDevExpDefaultException)
            {
                ho_Bx.Dispose();
                ho_By.Dispose();
                ho_Bz.Dispose();

                hv_Sample3DModuleTmp.Dispose();
                hv_ObjectModel3DBLeft.Dispose();
                hv_ObjectModel3DBLeftConnected.Dispose();
                hv_ObjectModel3DBLeftNew.Dispose();
                hv_Info.Dispose();

            }
        }

        public void checkAngleByHeightnew(HObject ho_ImageRef, out HTuple hv_topAngleOfTwoLines,
      out HTuple hv_midAngleOfTwoLines, out HTuple hv_downAngleOfTwoLines)
        {



            // Local iconic variables 

            HObject ho_ImageHeight = null, ho_RegionLeft = null;
            HObject ho_ImageReducedLeft = null, ho_ConnectedRegionsLeft = null;
            HObject ho_SelectedRegionLeft = null, ho_Rectangle = null, ho_RegionIntersection = null;
            HObject ho_ImageReducedLeftN = null;

            // Local control variables 

            HTuple hv_Width = new HTuple(), hv_Height = new HTuple();
            HTuple hv_Rowhbegin = new HTuple(), hv_Columnhbegin = new HTuple();
            HTuple hv_Rowhend = new HTuple(), hv_Columnhend = new HTuple();
            HTuple hv_AnglesTmp = new HTuple(), hv_meanBeginHeight = new HTuple();
            HTuple hv_meanEndHeight = new HTuple(), hv_preLeftIndex = new HTuple();
            HTuple hv_preLeftIndexSec = new HTuple(), hv_preRightIndex = new HTuple();
            HTuple hv_preRightIndexSec = new HTuple(), hv_abs_sub = new HTuple();
            HTuple hv_Index = new HTuple(), hv_Rows = new HTuple();
            HTuple hv_Columns = new HTuple(), hv_grayvalues = new HTuple();
            HTuple hv_maxgray = new HTuple(), hv_findLeftIndex = new HTuple();
            HTuple hv_findLeftIndexSec = new HTuple(), hv_valueabs = new HTuple();
            HTuple hv_leftLineFPX = new HTuple(), hv_leftLineFPY = new HTuple();
            HTuple hv_leftLineSPX = new HTuple(), hv_leftLineSPY = new HTuple();
            HTuple hv_lengthgray = new HTuple(), hv_findRightIndex = new HTuple();
            HTuple hv_findRightIndexSec = new HTuple(), hv_rightLineFPX = new HTuple();
            HTuple hv_rightLineFPY = new HTuple(), hv_rightLineSPX = new HTuple();
            HTuple hv_rightLineSPY = new HTuple(), hv_rowIntersection = new HTuple();
            HTuple hv_colIntersection = new HTuple(), hv_IsParllel = new HTuple();
            HTuple hv_angleinter = new HTuple(), hv_degres = new HTuple();
            HTuple hv_Exception = new HTuple(), hv_AnglesRes = new HTuple();
            HTuple hv_SelectedTmp = new HTuple(), hv_IndexTmp = new HTuple();
            HTuple hv_AbsAnglest = new HTuple(), hv_TotalAbsAnglest = new HTuple();
            HTuple hv_lengthAngles = new HTuple(), hv_topSeleted = new HTuple();
            HTuple hv_midSeleted = new HTuple(), hv_downSeleted = new HTuple();
            HTuple hv_sortTopSelected = new HTuple(), hv_sortMidSelected = new HTuple();
            HTuple hv_sortDownSelected = new HTuple(), hv_topAngleValue = new HTuple();
            HTuple hv_midAngleValue = new HTuple(), hv_downAngleValue = new HTuple();
            // Initialize local and output iconic variables 
            HOperatorSet.GenEmptyObj(out ho_ImageHeight);
            HOperatorSet.GenEmptyObj(out ho_RegionLeft);
            HOperatorSet.GenEmptyObj(out ho_ImageReducedLeft);
            HOperatorSet.GenEmptyObj(out ho_ConnectedRegionsLeft);
            HOperatorSet.GenEmptyObj(out ho_SelectedRegionLeft);
            HOperatorSet.GenEmptyObj(out ho_Rectangle);
            HOperatorSet.GenEmptyObj(out ho_RegionIntersection);
            HOperatorSet.GenEmptyObj(out ho_ImageReducedLeftN);
            hv_topAngleOfTwoLines = new HTuple();
            hv_midAngleOfTwoLines = new HTuple();
            hv_downAngleOfTwoLines = new HTuple();
            try
            {
                try
                {
                    ho_ImageHeight.Dispose();
                    ho_ImageHeight = new HObject(ho_ImageRef);


                    hv_Width.Dispose(); hv_Height.Dispose();
                    HOperatorSet.GetImageSize(ho_ImageHeight, out hv_Width, out hv_Height);
                    ho_RegionLeft.Dispose();
                    HOperatorSet.Threshold(ho_ImageHeight, out ho_RegionLeft, -25, 25);
                    ho_ImageReducedLeft.Dispose();
                    HOperatorSet.ReduceDomain(ho_ImageHeight, ho_RegionLeft, out ho_ImageReducedLeft
                        );
                    ho_ConnectedRegionsLeft.Dispose();
                    HOperatorSet.Connection(ho_RegionLeft, out ho_ConnectedRegionsLeft);
                    ho_SelectedRegionLeft.Dispose();
                    HOperatorSet.SelectShape(ho_ConnectedRegionsLeft, out ho_SelectedRegionLeft,
                        "area", "and", 100000, 1e10);
                    hv_Rowhbegin.Dispose(); hv_Columnhbegin.Dispose(); hv_Rowhend.Dispose(); hv_Columnhend.Dispose();
                    HOperatorSet.SmallestRectangle1(ho_SelectedRegionLeft, out hv_Rowhbegin,
                        out hv_Columnhbegin, out hv_Rowhend, out hv_Columnhend);



                    hv_AnglesTmp.Dispose();
                    hv_AnglesTmp = new HTuple();

                    hv_meanBeginHeight.Dispose();
                    hv_meanBeginHeight = 0;
                    hv_meanEndHeight.Dispose();
                    hv_meanEndHeight = 0;
                    hv_preLeftIndex.Dispose();
                    hv_preLeftIndex = -1;
                    hv_preLeftIndexSec.Dispose();
                    hv_preLeftIndexSec = -1;

                    hv_preRightIndex.Dispose();
                    hv_preRightIndex = -1;
                    hv_preRightIndexSec.Dispose();
                    hv_preRightIndexSec = -1;

                    hv_abs_sub.Dispose();
                    hv_abs_sub = 0.03;
                    HTuple end_val24 = hv_Rowhend - 100;
                    HTuple step_val24 = 5;
                    for (hv_Index = hv_Rowhbegin + 100; hv_Index.Continue(end_val24, step_val24); hv_Index = hv_Index.TupleAdd(step_val24))
                    {
                        try
                        {
                            ho_Rectangle.Dispose();
                            HOperatorSet.GenRectangle1(out ho_Rectangle, hv_Index, 0, hv_Index, 3100);
                            ho_RegionIntersection.Dispose();
                            HOperatorSet.Intersection(ho_Rectangle, ho_RegionLeft, out ho_RegionIntersection
                                );
                            ho_ImageReducedLeftN.Dispose();
                            HOperatorSet.ReduceDomain(ho_ImageReducedLeft, ho_RegionIntersection,
                                out ho_ImageReducedLeftN);
                            hv_Rows.Dispose(); hv_Columns.Dispose();
                            HOperatorSet.GetRegionPoints(ho_RegionIntersection, out hv_Rows, out hv_Columns);
                            hv_grayvalues.Dispose();
                            HOperatorSet.GetGrayval(ho_ImageReducedLeftN, hv_Rows, hv_Columns, out hv_grayvalues);

                            hv_maxgray.Dispose();
                            HOperatorSet.TupleMax(hv_grayvalues, out hv_maxgray);
                            if ((int)(new HTuple(hv_preLeftIndex.TupleEqual(-1))) != 0)
                            {
                                hv_findLeftIndex.Dispose();
                                hv_findLeftIndex = 0;
                            }
                            else
                            {
                                hv_findLeftIndex.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findLeftIndex = hv_preLeftIndex - 10;
                                }
                            }

                            if ((int)(new HTuple(hv_preLeftIndexSec.TupleEqual(-1))) != 0)
                            {
                                hv_findLeftIndexSec.Dispose();
                                hv_findLeftIndexSec = 0;
                            }
                            else
                            {
                                hv_findLeftIndexSec.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findLeftIndexSec = hv_preLeftIndexSec - 30;
                                }
                            }

                            while (true)
                            {
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_valueabs.Dispose();
                                    HOperatorSet.TupleAbs((hv_grayvalues.TupleSelect(hv_findLeftIndex)) - (hv_maxgray - 3),
                                        out hv_valueabs);
                                }
                                if ((int)(new HTuple(hv_valueabs.TupleLess(hv_abs_sub))) != 0)
                                {
                                    break;
                                }
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    {
                                        HTuple
                                          ExpTmpLocalVar_findLeftIndex = hv_findLeftIndex + 1;
                                        hv_findLeftIndex.Dispose();
                                        hv_findLeftIndex = ExpTmpLocalVar_findLeftIndex;
                                    }
                                }
                            }

                            hv_leftLineFPX.Dispose();
                            using (HDevDisposeHelper dh = new HDevDisposeHelper())
                            {
                                hv_leftLineFPX = hv_findLeftIndex * 0.015;
                            }
                            hv_leftLineFPY.Dispose();
                            using (HDevDisposeHelper dh = new HDevDisposeHelper())
                            {
                                hv_leftLineFPY = hv_grayvalues.TupleSelect(
                                    hv_findLeftIndex);
                            }



                            while (true)
                            {
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_valueabs.Dispose();
                                    HOperatorSet.TupleAbs((hv_grayvalues.TupleSelect(hv_findLeftIndexSec)) - (hv_maxgray - 2),
                                        out hv_valueabs);
                                }
                                if ((int)(new HTuple(hv_valueabs.TupleLess(hv_abs_sub))) != 0)
                                {
                                    break;
                                }
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    {
                                        HTuple
                                          ExpTmpLocalVar_findLeftIndexSec = hv_findLeftIndexSec + 1;
                                        hv_findLeftIndexSec.Dispose();
                                        hv_findLeftIndexSec = ExpTmpLocalVar_findLeftIndexSec;
                                    }
                                }
                            }

                            hv_preLeftIndex.Dispose();
                            hv_preLeftIndex = new HTuple(hv_findLeftIndex);
                            hv_preLeftIndexSec.Dispose();
                            hv_preLeftIndexSec = new HTuple(hv_findLeftIndexSec);

                            hv_leftLineSPX.Dispose();
                            using (HDevDisposeHelper dh = new HDevDisposeHelper())
                            {
                                hv_leftLineSPX = hv_findLeftIndexSec * 0.015;
                            }
                            hv_leftLineSPY.Dispose();
                            using (HDevDisposeHelper dh = new HDevDisposeHelper())
                            {
                                hv_leftLineSPY = hv_grayvalues.TupleSelect(
                                    hv_findLeftIndexSec);
                            }


                            hv_lengthgray.Dispose();
                            HOperatorSet.TupleLength(hv_grayvalues, out hv_lengthgray);

                            if ((int)(new HTuple(hv_preRightIndex.TupleEqual(-1))) != 0)
                            {
                                hv_findRightIndex.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findRightIndex = hv_lengthgray - 1;
                                }
                            }
                            else
                            {
                                hv_findRightIndex.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findRightIndex = hv_preRightIndex + 50;
                                }
                            }

                            if ((int)(new HTuple(hv_preRightIndexSec.TupleEqual(-1))) != 0)
                            {
                                hv_findRightIndexSec.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findRightIndexSec = hv_lengthgray - 1;
                                }
                            }
                            else
                            {
                                hv_findRightIndexSec.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findRightIndexSec = hv_preRightIndexSec + 50;
                                }
                            }


                            while (true)
                            {
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_valueabs.Dispose();
                                    HOperatorSet.TupleAbs((hv_grayvalues.TupleSelect(hv_findRightIndex)) - (hv_maxgray - 3),
                                        out hv_valueabs);
                                }
                                if ((int)(new HTuple(hv_valueabs.TupleLess(hv_abs_sub))) != 0)
                                {
                                    break;
                                }
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    {
                                        HTuple
                                          ExpTmpLocalVar_findRightIndex = hv_findRightIndex - 1;
                                        hv_findRightIndex.Dispose();
                                        hv_findRightIndex = ExpTmpLocalVar_findRightIndex;
                                    }
                                }
                            }

                            hv_rightLineFPX.Dispose();
                            using (HDevDisposeHelper dh = new HDevDisposeHelper())
                            {
                                hv_rightLineFPX = hv_findRightIndex * 0.015;
                            }
                            hv_rightLineFPY.Dispose();
                            using (HDevDisposeHelper dh = new HDevDisposeHelper())
                            {
                                hv_rightLineFPY = hv_grayvalues.TupleSelect(
                                    hv_findRightIndex);
                            }


                            while (true)
                            {
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_valueabs.Dispose();
                                    HOperatorSet.TupleAbs((hv_grayvalues.TupleSelect(hv_findRightIndexSec)) - (hv_maxgray - 2),
                                        out hv_valueabs);
                                }
                                if ((int)(new HTuple(hv_valueabs.TupleLess(hv_abs_sub))) != 0)
                                {
                                    break;
                                }
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    {
                                        HTuple
                                          ExpTmpLocalVar_findRightIndexSec = hv_findRightIndexSec - 1;
                                        hv_findRightIndexSec.Dispose();
                                        hv_findRightIndexSec = ExpTmpLocalVar_findRightIndexSec;
