        public void checkAngleByHeights(HObject ho_ImageRef, out HTuple hv_topAngleOfTwoLines,
     out HTuple hv_midAngleOfTwoLines, out HTuple hv_downAngleOfTwoLines)
        {



            // Local iconic variables 

            HObject ho_ImageHeight = null, ho_RegionLeft = null;
            HObject ho_ImageReducedLeft = null, ho_ConnectedRegionsLeft = null;
            HObject ho_SelectedRegionLeft = null, ho_Rectangle = null, ho_RegionIntersection = null;
            HObject ho_ImageReducedLeftN = null;

