            HTuple hv_rightLineFPX = new HTuple(), hv_rightLineFPY = new HTuple();
            HTuple hv_rightLineSPX = new HTuple(), hv_rightLineSPY = new HTuple();
            HTuple hv_rowIntersection = new HTuple(), hv_colIntersection = new HTuple();
            HTuple hv_IsParllel = new HTuple(), hv_angleinter = new HTuple();
            HTuple hv_degres = new HTuple(), hv_Exception = new HTuple();
            HTuple hv_AnglesRes = new HTuple(), hv_SelectedTmp = new HTuple();
            HTuple hv_IndexTmp = new HTuple(), hv_AbsAnglest = new HTuple();
            HTuple hv_TotalAbsAnglest = new HTuple(), hv_lengthAngles = new HTuple();
            HTuple hv_topSeleted = new HTuple(), hv_midSeleted = new HTuple();
            HTuple hv_downSeleted = new HTuple(), hv_sortTopSelected = new HTuple();
            HTuple hv_sortMidSelected = new HTuple(), hv_sortDownSelected = new HTuple();
