            HOperatorSet.GenEmptyObj(out ho_ConnectedRegionsLeft);
            HOperatorSet.GenEmptyObj(out ho_SelectedRegionLeft);
            HOperatorSet.GenEmptyObj(out ho_Rectangle);
            HOperatorSet.GenEmptyObj(out ho_RegionIntersection);
            HOperatorSet.GenEmptyObj(out ho_ImageReducedLeftN);
            hv_topAngleOfTwoLines = new HTuple();
            hv_midAngleOfTwoLines = new HTuple();
            hv_downAngleOfTwoLines = new HTuple();
            try
            {
                try
                {
                    ho_ImageHeight.Dispose();
                    ho_ImageHeight = new HObject(ho_ImageRef);


                    hv_Width.Dispose(); hv_Height.Dispose();
                    HOperatorSet.GetImageSize(ho_ImageHeight, out hv_Width, out hv_Height);
                    ho_RegionLeft.Dispose();
                    HOperatorSet.Threshold(ho_ImageHeight, out ho_RegionLeft, -25, 25);
                    ho_ImageReducedLeft.Dispose();
