                            {
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_valueabs.Dispose();
                                    HOperatorSet.TupleAbs((hv_grayvalues.TupleSelect(hv_findLeftIndex)) - 0,
                                        out hv_valueabs);
                                }
                                if ((int)(new HTuple(hv_valueabs.TupleLess(0.03))) != 0)
                                {
                                    break;
                                }
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    {
                                        HTuple
                                          ExpTmpLocalVar_findLeftIndex = hv_findLeftIndex + 1;
                                        hv_findLeftIndex.Dispose();
                                        hv_findLeftIndex = ExpTmpLocalVar_findLeftIndex;
                                    }
                                }
                            }

