                                    hv_findLeftIndexSec);
                            }


                            hv_lengthgray.Dispose();
                            HOperatorSet.TupleLength(hv_grayvalues, out hv_lengthgray);

                            if ((int)(new HTuple(hv_preRightIndex.TupleEqual(-1))) != 0)
                            {
                                hv_findRightIndex.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findRightIndex = hv_lengthgray - 1;
                                }
                            }
                            else
                            {
                                hv_findRightIndex.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findRightIndex = hv_preRightIndex + 15;
                                }
                            }

                            if ((int)(new HTuple(hv_preRightIndexSec.TupleEqual(-1))) != 0)
                            {
                                hv_findRightIndexSec.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findRightIndexSec = hv_lengthgray - 1;
                                }
                            }
                            else
                            {
                                hv_findRightIndexSec.Dispose();
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    hv_findRightIndexSec = hv_preRightIndexSec + 15;
