                                    hv_valueabs.Dispose();
                                    HOperatorSet.TupleAbs((hv_grayvalues.TupleSelect(hv_findRightIndex)) - 0,
                                        out hv_valueabs);
                                }
                                if ((int)(new HTuple(hv_valueabs.TupleLess(0.03))) != 0)
                                {
                                    break;
                                }
                                using (HDevDisposeHelper dh = new HDevDisposeHelper())
                                {
                                    {
                                        HTuple
                                          ExpTmpLocalVar_findRightIndex = hv_findRightIndex - 1;
                                        hv_findRightIndex.Dispose();
                                        hv_findRightIndex = ExpTmpLocalVar_findRightIndex;
